const data = [];
// 該当する年の最初から最後までダミーの日付データを生成しつつ、提供されたrowsをマージする関数
const year = '2026';
let currentDate = new Date(year + '-01-01');
const endDate = new Date(year + '-12-31');
const valMap = {};
rawData.rows.forEach(r => { valMap[r.date] = r.value; });

while(currentDate <= endDate) {
  const dStr = currentDate.toISOString().split('T')[0];
  const val = valMap[dStr] || Math.floor(Math.random() * 20); // 未定義の日はノイズデータを追加
  data.push([dStr, val]);
  currentDate.setDate(currentDate.getDate() + 1);
}
transformedData = data;

